steps.script:
var models = GameState.state.units["U_WITCHSEEKERS_D"]["models"]
for i in range(models.size()):
	models[i]["position"] = {"x": 950.0 + (i % 2) * 42.0, "y": 1660.0 + int(i / 2.0) * 42.0}
return models.size()

var ph = PhaseManager.get_current_phase_instance()
if ph.pending_assignments.size() != 1:
	return "expected 1 assignment, got %d" % ph.pending_assignments.size()
var a = ph.pending_assignments[0]
return str(a.target_unit_id) + ":" + str((a.model_ids as Array).size())

var sc = tree.current_scene.shooting_controller
var d = sc.get_node_or_null("SplitFirePicker")
if d == null:
	return "no dialog"
var spin = d.find_child("SplitFireSpin", true, false)
return str(int(spin.value)) + "/" + str(int(spin.max_value))

var sc = tree.current_scene.shooting_controller
var d = sc.get_node_or_null("SplitFirePicker")
var spin = d.find_child("SplitFireSpin", true, false)
return int(spin.value)

var ph = PhaseManager.get_current_phase_instance()
var by_target = {}
for a in ph.pending_assignments:
	by_target[str(a.target_unit_id)] = (a.model_ids as Array).size()
return str(by_target.get("U_BATTLEWAGON_G", 0)) + "+" + str(by_target.get("U_BOYZ_E", 0))
